import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

# Build lookup: project_name -> framework -> package -> version
def build_index(data):
    idx = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        idx[name] = {}
        for fw in proj['frameworks']:
            idx[name][fw['framework']] = {p['id']: p['resolvedVersion'] for p in fw['topLevelPackages']}
    return idx

b = build_index(baseline)
a = build_index(after)

changes = []
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    for fw in sorted(set(list(b.get(proj,{}).keys()) + list(a.get(proj,{}).keys()))):
        bp = b.get(proj,{}).get(fw,{})
        ap = a.get(proj,{}).get(fw,{})
        for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
            bv = bp.get(pkg, 'N/A')
            av = ap.get(pkg, 'N/A')
            if bv != av:
                changes.append(f'{proj} [{fw}] {pkg}: {bv} -> {av}')

if changes:
    print('VERSION CHANGES:')
    for c in changes: print(f'  {c}')
else:
    print('No version changes - all packages resolve identically to baseline.')
"

